const request = $input.first().json;
const companySize = request.company_size || 'mid';
const industry = request.industry || 'general';
const automationLevel = request.current_automation || 'none';
const assessment = {
  company_size: companySize,
  industry: industry,
  current_automation: automationLevel,
  readiness_score: 0
};
if (companySize === 'enterprise') assessment.readiness_score += 30;
else if (companySize === 'mid') assessment.readiness_score += 20;
else assessment.readiness_score += 10;
if (automationLevel === 'advanced') assessment.readiness_score += 40;
else if (automationLevel === 'moderate') assessment.readiness_score += 25;
else if (automationLevel === 'basic') assessment.readiness_score += 10;
const highValueIndustries = ['finance', 'healthcare', 'retail', 'manufacturing'];
if (highValueIndustries.includes(industry.toLowerCase())) assessment.readiness_score += 30;
assessment.priority = assessment.readiness_score >= 70 ? 'high' : assessment.readiness_score >= 40 ? 'medium' : 'low';
assessment.recommended_services = [];
if (assessment.readiness_score < 30) assessment.recommended_services.push('Automation Assessment', 'Tool Selection');
else if (assessment.readiness_score < 60) assessment.recommended_services.push('Process Automation', 'Integration Services');
else assessment.recommended_services.push('AI Strategy', 'Custom Development', 'MLOps');
return { ...request, ...assessment };

